# D - Cut and Stick
## Description
[题目链接](https://codeforces.com/contest/1514/problem/D)
## Solution
对于区间 $[l,r]$，设出现次数最多的数的出现次数为 $x$。

- 若 $x \le \lceil \frac{r-l+1}{2} \rceil$，则只需要分 1 组。

- 若 $x > \lceil \frac{r-l+1}{2} \rceil$，显然其余 $(r-l+1)-x$ 个数的出现次数均严格小于 $\lceil \frac{r-l+1}{2} \rceil$。我们只需要在出现次数最多的数中选出 $(r-l+1)-x+1$ 个分成一组，其余 $2x-(r-l+1) -1$ 个单独分组。这样一共分成 $2x-(r-l+1)$ 组。

求区间出现次数最多的数的出现次数可以用莫队。参考这道题：[大爷的字符串题](https://www.luogu.com.cn/problem/P3709)
## Code
```cpp Cut and Stick
#include <bits/stdc++.h>

using namespace std;
const int MAXN = 3e5 + 5;
int n, m, sz, tot;
int color[MAXN], belong[MAXN], ans[MAXN], cnt[MAXN], num[MAXN];
vector<int> v;

template <class T>
void read(T& x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Query {
    int l, r, id;
    friend bool operator<(const Query& a, const Query& b) {
        if (belong[a.l] == belong[b.l]) {
            if (belong[a.l] & 1) return a.r < b.r;
            return a.r > b.r;
        }
        return a.l < b.l;
    }
} q[MAXN];

void Add(int x) {
    num[cnt[x]]--;
    cnt[x]++;
    num[cnt[x]]++;
    tot = max(tot, cnt[x]);
}

void Sub(int x) {
    num[cnt[x]]--;
    if (cnt[x] == tot && !num[cnt[x]]) tot--;
    cnt[x]--;
    num[cnt[x]]++;
}

int main() {
    read(n), read(m);
    sz = max(1, int(n / sqrt(m)));
    for (int i = 1; i <= n; i++) {
        read(color[i]);
        belong[i] = i / sz;
    }
    for (int i = 1; i <= m; i++) {
        read(q[i].l), read(q[i].r);
        q[i].id = i;
    }
    sort(q + 1, q + m + 1);
    int l = 0, r = 0;
    num[0] = n;
    for (int i = 1; i <= m; i++) {
        while (l > q[i].l) Add(color[--l]);
        while (r < q[i].r) Add(color[++r]);
        while (l < q[i].l) Sub(color[l++]);
        while (r > q[i].r) Sub(color[r--]);
        ans[q[i].id] = max(1, 2 * tot - (q[i].r - q[i].l + 1));
    }
    for (int i = 1; i <= m; i++) printf("%d\n", ans[i]);
    return 0;
}
```

