# B Tiling Dominoes
[题目链接](https://www.luogu.com.cn/problem/UVA11270)
## Desciption 
求用 $2*1$ 的方块填满 $H*W$ 的方格的方案数。
## Solution
上一题的弱化版本。由于方块数目没有限制，故只需要设 $dp[i][s]$ 表示考虑前 $i$ 个方格，从这个方格开始前 $W$ 个方格填充状态为 $s$，除了这些方格外其余方格全部被填满的方案数。现在考虑第 $i+1$ 个方格，根据 $s'$，$s_u$ 和 $s_l$（和上一题题解中的定义一致），有如下转移：

- $s_u = 0$，则必须竖着放一个 $2*1$ 的方块，于是有：
$$dp[i+1][s'|1][a+1][b] \leftarrow dp[i][s][a][b]$$
- $s_l s_u = 01$，则可以横着放一个 $2*1$ 的方块，或者不放，从而：
$$
\begin{aligned}
dp[i+1][s'|3][a+1][b] \leftarrow dp[i][s][a][b] \\
dp[i+1][s'][a][b] \leftarrow dp[i][s][a][b]     \\
 \end{aligned}
$$

- $s_l s_u = 11$，只能不放，故有：
$$
\begin{aligned}
dp[i+1][s'][a][b] \leftarrow dp[i][s][a][b]     \\
 \end{aligned}
$$

最后答案为 $dp[H*W][(1<<W)-1]$。

类似题目：[HDU1400 Mondriaan's Dream](http://acm.hdu.edu.cn/showproblem.php?pid=1400)
## Code
```cpp Tiling Dominoes
#include <bits/stdc++.h>

#define debug(x) cerr << #x << " = " << x << endl

using namespace std;
typedef long long LL;

int H, W, T;

void add(LL& a, LL b) { a = a + b; }

signed main() {
    while (cin >> H >> W) {
        if (W > H) swap(H, W);
        LL dp[2][1 << W];
        memset(dp, 0, sizeof(dp));
        dp[0][(1 << W) - 1] = 1;
        bool tag = 0;
        for (int i = 1; i <= H; i++)
            for (int j = 1; j <= W; j++) {
                tag ^= 1;
                memset(dp[tag], 0, sizeof(dp[tag]));
                for (int s = 0; s < (1 << W); s++) {
                    int nxtS = ((s << 1) & ((1 << W) - 1));
                    int sUp = (s >> (W - 1)) | (i == 1);
                    int sLeft = (s & 1) | (j == 1);
                    if (!sUp)
                        add(dp[tag][nxtS | 1], dp[tag ^ 1][s]);
                    else if (!sLeft) {
                        add(dp[tag][nxtS | 3], dp[tag ^ 1][s]);
                        add(dp[tag][nxtS], dp[tag ^ 1][s]);
                    } else
                        add(dp[tag][nxtS], dp[tag ^ 1][s]);
                }
            }
        cout << dp[tag][(1 << W) - 1] << endl;
    }
    return 0;
}
```

# C Campus Design
## Desciption 
[题目链接](http://acm.hdu.edu.cn/showproblem.php?pid=4804)
## Solution
限制了 $1*1$ 的方块的使用次数，同时有一些方格已被占用。虽然增加了一些约束，但解法和第一题基本相同，不再赘述。
## Code
```cpp Campus Design
#include <bits/stdc++.h>

#define debug(x) cerr << #x << " = " << x << endl

using namespace std;

const int MOD = 1E9 + 7;
int H, W, C, D;

void add(int& a, int b) { a = (a + b) % MOD; }

signed main() {
    ios::sync_with_stdio(false);
    while (cin >> H >> W >> C >> D) {
        int dp[2][1 << W][D + 1];
        char c[H + 1][W + 1];
        for (int i = 1; i <= H; i++)
            for (int j = 1; j <= W; j++) cin >> c[i][j];
        memset(dp, 0, sizeof(dp));
        dp[0][(1 << W) - 1][0] = 1;
        bool tag = 0;
        for (int i = 1; i <= H; i++)
            for (int j = 1; j <= W; j++) {
                tag ^= 1;
                memset(dp[tag], 0, sizeof(dp[tag]));
                for (int s = 0; s < (1 << W); s++)
                    for (int b = 0; b <= D; b++) {
                        int nxtS = ((s << 1) & ((1 << W) - 1));
                        int sUp = (s >> (W - 1)) | (i == 1);
                        int sLeft = (s & 1) | (j == 1);
                        if (!sUp) {
                            if (c[i][j] == '1')
                                add(dp[tag][nxtS | 1][b], dp[tag ^ 1][s][b]);
                        } else if (!sLeft) {
                            if (c[i][j] == '1') {
                                add(dp[tag][nxtS | 3][b], dp[tag ^ 1][s][b]);
                                if (b)
                                    add(dp[tag][nxtS | 1][b],
                                        dp[tag ^ 1][s][b - 1]);
                            }
                            add(dp[tag][nxtS | (c[i][j] == '0')][b],
                                dp[tag ^ 1][s][b]);
                        } else {
                            if (b && c[i][j] == '1')
                                add(dp[tag][nxtS | 1][b],
                                    dp[tag ^ 1][s][b - 1]);
                            add(dp[tag][nxtS | (c[i][j] == '0')][b],
                                dp[tag ^ 1][s][b]);
                        }
                    }
            }
        int ans = 0;
        for (int i = C; i <= D; i++) add(ans, dp[tag][(1 << W) - 1][i]);
        cout << ans << endl;
    }
    return 0;
}
```

