## Solution
- 询问在有向图中从起点出发回到起点的最短回路。

- 先求出单源最短路，由于 $dist_start$ 初始值为0，故需枚举每个点 $i$，答案为 $dist_i + w_{i, start}$ 的最小值。

## Code
```cpp Come Back Quickly
#include <bits/stdc++.h>

using namespace std;

#define debug(x) cerr << #x << " = " << x << endl
#define boost ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);

constexpr int MAXN = 2002, MOD = 1e9 + 7;

int n, m;
vector<pair<int, int>> g[MAXN];
array<int, MAXN> dis, inq, self;

void spfa(int st) {
    for (int i = 1; i <= n; i++) dis[i] = 1e9, inq[i] = false;
    queue<int> q;
    q.push(st), inq[st] = true;
    dis[st] = 0;
    while (!q.empty()) {
        int cur = q.front();
        q.pop();
        inq[cur] = false;
        for (auto& e : g[cur]) {
            int to = e.first, w = e.second;
            if (dis[to] > dis[cur] + w) {
                dis[to] = dis[cur] + w;
                if (!inq[to]) {
                    q.push(to);
                    inq[to] = true;
                }
            }
        }
    }
    int ans = 1e9;
    for (int i = 1; i <= n; i++) {
        for (auto & e : g[i]) {
            if (e.first == st) {
                ans = min(ans, dis[i] + e.second);
            }
        }
    }
    if (ans != 1e9) cout << ans << "\n";
    else cout << "-1\n";
}


signed main() {
    boost;
    cin >> n >> m;
    for (int i = 1; i <= m; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        g[u].push_back({v, w});
    }
    for (int i = 1; i <= n; i++) spfa(i);
    return 0;
}
