    LL ans = INT_MAX;
    for (int j = 0; j <= 10; j++) {
        if (j == 0 && b == 1) continue;
        LL tmp = 0;
        while (qpow(b + j, tmp) <= a) tmp++;
        ans = min(ans, tmp + j);
    }
    cout << ans << endl;
}
