    ios::sync_with_stdio(false);
    cin.tie(0);
    cin >> n;
    dp[0][1] = dp[0][0] = 1;
    for (int i = 1; i <= n; i++) {
        cin >> s;
        if (s == "AND") {
            dp[i][1] = dp[i - 1][1];
            dp[i][0] = dp[i - 1][1] + dp[i - 1][0] * 2;
