# B Ternary Sequence
考虑 $a$ 序列，$a$ 的 2 优先和 $b$ 的 1 匹配，若有剩余再和 $b$ 的 2 匹配。然后 2 和 0， 0 和 2 匹配。最后只能 2 和 1 匹配。
```cpp Ternary Sequence
#include <bits/stdc++.h>
#define int long long

using namespace std;

constexpr int MAXN = 2e5 + 5, MOD = 1e9 + 7;

int tc, n, m, x[2], y[2], z[2];

signed main() {
    ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> tc;
    while (tc--) {
        int ans = 0;
        cin >> x[0] >> y[0] >> z[0];
        cin >> x[1] >> y[1] >> z[1];
        int tmp = min(z[0], y[1]); //2 1
        ans += 2LL * tmp;

        z[0] -= tmp, y[1] -= tmp; // 2 2
        tmp = min(z[0], z[1]);
        z[0] -= tmp, z[1] -= tmp;

        tmp = min(z[0], x[1]); //2 0
        z[0] -= tmp, x[1] -= tmp;

        tmp = min(z[1], x[0]); //0 2
        z[1] -= tmp, x[0] -= tmp;

        tmp = min(z[0], y[1]);
        ans -= 2LL * tmp;

        tmp = min(z[1], y[0]);
        ans -= 2LL * tmp;

        cout << ans << "\n";
    }
    return 0;
}
