# SP10707 COT2 - Count on a tree II
## Description
[题目链接](https://www.luogu.com.cn/problem/SP10707)
## Solution1
采用王室联邦分块法。对于所有询问 $\{(u_i,v_i)\}$，按 $u_i$ 所属块编号从小到大排序，若 $u_i$ 所属块相同按 $v_i$ 所属块编号从小到大排序。至于奇偶性优化...也许有点用，还是加上吧。

接下来两个查询间如何转移。设 $S_{u,v}$ 为路径 $u-v$ 上的所有点的集合，$T_{u,v}$表示路径 $u-v$ 上的除 $lca(u,v)$ 外的点构成的集合。设上一次询问为 $(u,v)$，本次询问为 $(u',v')$。那么上一次询问涉及到的节点为 $S_{u,v}=T_{u,v}∪lca(u,v)$，本次询问涉及到的节点为 $S_{u',v'}=T_{u',v'}∪lca(u',v')$。定义 ⊕ 表示集合的对称差运算，由 ⊕ 的交换律和结合律，有：

$T_{u',v'}=T_{u',v'}⊕T_{u,v}⊕T_{v,u}$

$=(S_{u',rt}⊕S_{rt,v'})⊕(S_{u,rt}⊕S_{rt,v})⊕T_{u,v}$

$=(S_{u',rt}⊕S_{u,rt})⊕(S_{rt,v}⊕S_{rt,v'})⊕T_{u,v}$

$=T_{u,u'}⊕T_{v,v'}⊕T_{u,v}$

$=T_{u,u'}⊕T_{v,v'}⊕S_{u,v}⊕lca(u,v)$

$= S_{u',v'}⊕lca(u',v')$

移项可得：$S_{u',v'}=lca(u',v')⊕lca(u,v)⊕T_{u,u'}⊕T_{v,v'}⊕S_{u,v}$

求 $lca$ 可用树链剖分(相比倍增常数小)，在 $dfs$ 分块时可顺便维护。
对于异或操作，可用一个数组记录每个节点是否在集合中。每更新一个节点，若其在集合中则将相应数值删除，否则加入集合。至于 $T_{u,u'}$ 和 $T_{v,v'}$，分别直接遍历整个链，更新直至 $lca$ 处停止即可。

## Code1
```cpp Count on a tree II
#include <bits/stdc++.h>

using namespace std;

const int MAXN = 1e5 + 5;

int n, m, B, cntB, tot;
int val[MAXN], p[MAXN], belong[MAXN], ans[MAXN], cntC[MAXN];
int hson[MAXN], sz[MAXN], dep[MAXN], f[MAXN], top[MAXN];
bool vis[MAXN];
vector<int> v;

template <class T>
void read(T &x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Edge {
    int to, nxt;
} e[MAXN * 2];

struct Query {
    int x, y, id;
    friend bool operator<(const Query &a, const Query &b) {
        if (belong[a.x] == belong[b.x]) {
            if (belong[a.x] & 1) return belong[a.y] < belong[b.y];
            return belong[a.y] > belong[b.y];
        }
        return belong[a.x] < belong[b.x];
    }
} q[MAXN * 3];

void addEdge(int from, int to) {
    static int t;
    e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}

stack<int> s;
void dfs(int now, int fa) {
    sz[now] = 1, dep[now] = dep[fa] + 1, f[now] = fa;
    int tmp = s.size();
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != fa) {
            dfs(to, now);
            sz[now] += sz[to];
            if (!hson[now] || sz[to] > sz[hson[now]]) hson[now] = to;
            if (s.size() - tmp >= B) {
                cntB++;
                while (s.size() > tmp) {
                    int cur = s.top();
                    s.pop();
                    belong[cur] = cntB;
                }
            }
        }
    }
    s.push(now);
}

void dfs2(int now, int tp) {
    top[now] = tp;
    if (!hson[now]) return;
    dfs2(hson[now], tp);
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != f[now] && to != hson[now]) dfs2(to, to);
    }
}

int lca(int u, int v) {
    if (dep[top[u]] < dep[top[v]]) swap(u, v);
    while (top[u] != top[v]) {
        u = f[top[u]];
        if (dep[top[u]] < dep[top[v]]) swap(u, v);
    }
    if (dep[u] < dep[v]) swap(u, v);
    return v;
}

void getBlock() {
    B = sqrt(n);
    dfs(1, 1);
    dfs2(1, 1);
    if (!cntB) ++cntB;
    while (!s.empty()) {
        int tmp = s.top();
        s.pop();
        belong[tmp] = cntB;
    }
}

void discretize() {
    sort(v.begin(), v.end());
    for (int i = 1; i <= n; i++)
        val[i] = lower_bound(v.begin(), v.end(), val[i]) - v.begin() + 1;
}

void modify(int now) {
    if (!vis[now]) {
        ++cntC[val[now]];
        if (cntC[val[now]] == 1) tot++;
    } else {
        --cntC[val[now]];
        if (cntC[val[now]] == 0) tot--;
    }
    vis[now] ^= 1;
}

void update(int u, int v) {
    if (dep[u] < dep[v]) swap(u, v);
    while (dep[u] > dep[v]) modify(u), u = f[u];
    while (u != v) modify(u), modify(v), u = f[u], v = f[v];
}

int main() {
    read(n), read(m);
    for (int i = 1; i <= n; i++) read(val[i]), v.push_back(val[i]);
    discretize();
    fill(p + 1, p + n + 1, -1);
    int x(0), y(0);
    for (int i = 1; i <= n - 1; i++) {
        read(x), read(y);
        addEdge(x, y), addEdge(y, x);
    }
    getBlock();
    for (int i = 1; i <= m; i++) {
        read(q[i].x), read(q[i].y);
        q[i].id = i;
    }
    sort(q + 1, q + m + 1);
    x = 1, y = 1;
    modify(1);
    for (int i = 1; i <= m; i++) {
        int lca1 = lca(x, y), lca2 = lca(q[i].x, q[i].y);
        update(x, q[i].x), x = q[i].x;
        update(y, q[i].y), y = q[i].y;
        modify(lca1), modify(lca2);
        ans[q[i].id] = tot;
    }
    for (int i = 1; i <= m; i++) printf("%d\n", ans[i]);
    return 0;
}
```

## Solution2
考虑把树上的问题转化到序列上。

这里引入欧拉序，它的思想是：当访问到点$i$ 时，加入序列，记录时间戳 $in[i]$，然后访问 $i$ 的子树，当访问完时，再把 $i$ 加入序列，并记录时间戳 $out[i]$。如果将一条链映射到序列中的一段区间，那么这个区间中出现两次的节点一定不属于这条链（两端点的 $lca$）除外, 这样只需要统计出现一次的节点即可。

对于一条链 $(u,v)$，设 $in[u]<in[v]$，讨论两种情况：
- $lca(u,v)=u$，统计欧拉序在 $[in[u],in[v]]$ 的节点即可。
- $lca(u,v)\neq u$，统计欧拉序在 $[out[u],in[v]]$ 的节点，同时加上 $lca(u,v)$ 即可。

注：
- 这里求 $lca$ 依然使用树链剖分。
- 对于上述第二种情况，不取 $[in[u],in[v]]$ 是因为这样会导致 $u$ 在序列中出现两次。另外， $(in[u],out[u])$ 间的节点在 $u$ 的子树中，这些节点显然没有必要统计。
- 分块时需要注意序列长度为 $2n$。

## Code2
```cpp Count on a tree II
#include <bits/stdc++.h>

using namespace std;

const int MAXN = 1e5 + 5;

int n, m, B, tot;
int val[MAXN], p[MAXN], in[MAXN], out[MAXN], from[MAXN * 2];
int belong[MAXN * 2], ans[MAXN], cntC[MAXN];
int hson[MAXN], sz[MAXN], dep[MAXN], f[MAXN], top[MAXN];
bool vis[MAXN];
vector<int> v;

template <class T>
void read(T &x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Edge {
    int to, nxt;
} e[MAXN * 2];

struct Query {
    int l, r, id, lca;
    friend bool operator<(const Query &a, const Query &b) {
        if (belong[a.l] == belong[b.l]) {
            if (belong[a.l] & 1) return belong[a.r] < belong[b.r];
            return belong[a.r] > belong[b.r];
        }
        return belong[a.l] < belong[b.l];
    }
} q[MAXN * 3];

void addEdge(int from, int to) {
    static int t;
    e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}

void dfs(int now, int fa) {
    static int tim = 1;
    in[now] = tim, from[tim++] = now;
    sz[now] = 1, dep[now] = dep[fa] + 1, f[now] = fa;
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != fa) {
            dfs(to, now);
            sz[now] += sz[to];
            if (!hson[now] || sz[to] > sz[hson[now]]) hson[now] = to;
        }
    }
    out[now] = tim, from[tim++] = now;
}

void dfs2(int now, int tp) {
    top[now] = tp;
    if (!hson[now]) return;
    dfs2(hson[now], tp);
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != f[now] && to != hson[now]) dfs2(to, to);
    }
}

int lca(int u, int v) {
    if (dep[top[u]] < dep[top[v]]) swap(u, v);
    while (top[u] != top[v]) {
        u = f[top[u]];
        if (dep[top[u]] < dep[top[v]]) swap(u, v);
    }
    if (dep[u] < dep[v]) swap(u, v);
    return v;
}

void discretize() {
    sort(v.begin(), v.end());
    for (int i = 1; i <= n; i++)
        val[i] = lower_bound(v.begin(), v.end(), val[i]) - v.begin() + 1;
}

void modify(int now) {
    if (!vis[now]) {
        ++cntC[val[now]];
        if (cntC[val[now]] == 1) tot++;
    } else {
        --cntC[val[now]];
        if (cntC[val[now]] == 0) tot--;
    }
    vis[now] ^= 1;
}

int main() {
    read(n), read(m);
    for (int i = 1; i <= n; i++) read(val[i]), v.push_back(val[i]);
    discretize();
    fill(p + 1, p + n + 1, -1);
    int x(0), y(0);
    for (int i = 1; i <= n - 1; i++) {
        read(x), read(y);
        addEdge(x, y), addEdge(y, x);
    }
    B = max(1, 2 * n / (int)sqrt(m));
    dfs(1, 1), dfs2(1, 1);
    for (int i = 1; i <= m; i++) {
        read(x), read(y);
        if (in[x] > in[y]) swap(x, y);
        q[i].lca = lca(x, y);
        if (q[i].lca == x) {
            q[i].l = in[x];
            q[i].r = in[y];
            q[i].lca = 0;
        } else {
            q[i].l = out[x];
            q[i].r = in[y];
        }
        q[i].id = i;
    }
    for (int i = 1; i <= 2 * n; i++) belong[i] = (i - 1) / B + 1;
    sort(q + 1, q + m + 1);
    x = 1, y = 0;
    for (int i = 1; i <= m; i++) {
        while (x < q[i].l) modify(from[x++]);
        while (x > q[i].l) modify(from[--x]);
        while (y > q[i].r) modify(from[y--]);
        while (y < q[i].r) modify(from[++y]);
        if (q[i].lca) modify(q[i].lca);
        ans[q[i].id] = tot;
        if (q[i].lca) modify(q[i].lca);
    }
    for (int i = 1; i <= m; i++) printf("%d\n", ans[i]);
    return 0;
}
