# D Moving Piece
## Description
有 $n$ 个格子排成一列。给定 $1, 2, ..., n$ 的排列 $P_1, P_2, ..., P_n$，以及数组$C_1, C_2, ..., C_n$，表示格子 $i$ 能达到 $P_i$，获得的分数为 $C_{P_i}$。从任意一点出发走 $K$ 步，求能获得的最大分数。
## Solution
$O(N^2)$：
以每个点作为起点 $st$，求出路径，记录环的起点 $cyBeg$ 和终点 $cyEnd$ (终点指再走一步能回到环的起点的节点)。
求起点 $st$ 到 $cyEnd$ 的 $C$ 前缀和，以及前缀和中的最大值。并求出环上的 $C$ 总和，以及从 $cyBeg$ 开始的前缀和及其最大值。
判断能否走完整个环，若环为正环，则可以一直走到若干圈直到不能再走完整个环，或者少走一圈再加上前缀和最大值 (虽然环是正环，但可能环上存在一个极小值，少走一圈反而能使答案更大)。
$O(nlogn)$：
通过 $P$ 求出每个点的入度，从入度为 0 的点开始 $dfs$ 建图 (若没有点入度为 0，则所有点在环上，任意找一个点为起点即可)，并记录每个点是否在环上。分起点在环上和不在环上，起点在环上需分段讨论，然后可用支持区间修改查询的数据结构维护区间最大值。也有multiset做法 [link](https://codeforces.ml/blog/entry/81458?#comment-681192)。
## Code
```cpp Moving Piece O(N^2)
#include <bits/stdc++.h>
#define int long long

using namespace std;

constexpr int MAXN = 5e3 + 5;

int n, k, ans(-1e18), cyBeg, cyEnd;
array<int, MAXN> to, c, vis, pre, preMax;
vector<int> node;

inline void dfs(int cur) {
    vis[cur] = true;
    node.push_back(cur);
    if (vis[to[cur]]) {
        cyEnd = node.size() - 1; //环终点
        for (int i = 0; i < node.size(); i++)
            if (node[i] == to[cur]) {
                cyBeg = i; //环起点
                break;
            }
    }
    else dfs(to[cur]);
}

inline void search(int st) {
    node.clear();
    fill(vis.begin(), vis.end(), 0);
    fill(pre.begin(), pre.end(), 0);
    fill(preMax.begin(), preMax.end(), -1e18);
    cyBeg = cyEnd = -1;
    dfs(st);
    for (int i = 1; i < node.size(); i++)
        pre[i] = pre[i - 1] + c[node[i]], preMax[i] = max(preMax[i - 1], pre[i]);
    ans = max(ans, preMax[min(k, (int)node.size() - 1)]);
    if (k <= cyEnd || cyBeg == - 1 || cyEnd == -1) return;
    if (cyBeg == 0) { //一开始就有环
        int valC = pre[cyEnd] + c[node[cyBeg]];
        if (valC < 0) return;
        int tim = k / node.size(), res = k % node.size();
        ans = max(ans, tim * valC + max(0LL, preMax[res]));
        ans = max(ans, (tim - 1) * valC + max(0LL, preMax[cyEnd]));
        return;
    }
    int tmp = pre[cyBeg - 1];
    fill(pre.begin(), pre.end(), 0);
    fill(preMax.begin(), preMax.end(), -1e18);
    int valC = 0, cSize = cyEnd - cyBeg + 1, tim, res;
    for (int i = cyBeg; i <= cyEnd; i++) { //环上前缀和
        valC += c[node[i]];
        pre[i] = pre[i - 1] + c[node[i]];
        preMax[i] = max(preMax[i - 1], pre[i]);
    }
    if (valC < 0) return;
    k -= cyBeg - 1, tim = k / cSize, res = k % cSize;
    ans = max(ans, tmp + valC * tim + max(0LL, preMax[cyBeg + res - 1]));
    ans = max(ans, tmp + valC * (tim - 1) + max(0LL, preMax[cyEnd]));
}

signed main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> k;
    for (int i = 1; i <= n; i++) cin >> to[i];
    for (int i = 1; i <= n; i++) cin >> c[i];
    for (int i = 1; i <= n; i++) search(i);
    cout << ans << endl;
    return 0;
}
```

# E Picking Goods
## Description
[题目链接](https://atcoder.jp/contests/abc175/tasks/abc175_e)
## Solution
设 $dp[i][j][k]$ 表示当前为第 $i$ 行，第$j$ 列，第 $i$ 行选了 $k$ 个数的最大值。状态转移明显。
## Code
```cpp Picking Goods
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 3e3 + 3;

LL R, C, K;
LL dp[MAXN][MAXN][5], mp[MAXN][MAXN];

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> R >> C >> K;
    for (int i = 1; i <= K; i++) {
        int r, c, v;
        cin >> r >> c >> v;
        mp[r][c] = v;
    }
    for (int i = 1; i <= R; i++)
        for (int j = 1; j <= C; j++) {
            for (int cnti = 0; cnti < 4; cnti++) {
                    //不选
                    dp[i][j][cnti] = max(dp[i][j][cnti], dp[i][j - 1][cnti]);
                    for (int cntj = 0; cntj < 4; cntj++)
                        dp[i][j][cnti] = max(dp[i][j][cnti], dp[i - 1][j][cntj]);
                    //选
                    dp[i][j][cnti + 1] = max(dp[i][j][cnti + 1], dp[i][j - 1][cnti] + mp[i][j]);
                    for (int cntj = 0; cntj < 4; cntj++)
                        dp[i][j][cnti + 1] = max(dp[i][j][cnti + 1], dp[i - 1][j][cntj] + mp[i][j]);
            }
        }
    LL ans = 0;
    for (int i = 0; i < 4; i++) ans = max(ans, dp[R][C][i]);
    cout << ans << endl;
    return 0;
}

```

# F Making Palindrome
## Description
求将一些字符串 $S_1, S_2, ..., S_n$ 拼接为回文串的最小代价 ( $S_i$ 可多次被选，每选一次代价为 $C_i$ )。不能拼成回文串则输出 -1。
## Solution
将目标回文串分为左右两部分，设左边的字符串为 $l = s_{l_1}, s_{l_2}, ..., s_{l_j}$，右边的字符串为 $r = s_{r_k}, ..., s_{r_2}, s_{r_1}$。要使 $l, r$ 构成回文串，则需要 $s_{l_1}$ 的前缀与 $s_{r_1}$ 回文，或者 $s_{l_1}$ 与 $s_{r_1}$ 的后缀回文，并且将回文部分消去后的 $l, r$ 也满足上述条件 (此时 $s_{l_i}$ 和 $s_{r_i}$ 可能只是 $S$ 的一部分)。
于是可以考虑设当前状态为 $state = \{ string_l, string_r \}$，向字符串长度小的一边加入新字符串进行拼接，并消去回文部分，直到 $l, r$ 都为空，或者一个是回文串，一个是空串为止，然后跑 $dijkstra$ 即可。

## Code
```cpp Making Palindrome
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 55;

struct Node {
    Node() = default;
    Node(LL _c, string& _l, string& _r) : c(_c), l(_l), r(_r) {}
    LL c;
    string l, r;
    friend inline bool operator<(const Node& lhs, const Node& rhs) {
        return lhs.c > rhs.c;
    }
};
LL n, cost[MAXN];
string s[MAXN], emps("");

inline bool isPalindrome(const string& tmp) {
    for (int i = 0; i < tmp.size() /2 + 1; i++)
        if (tmp[i] != tmp[tmp.size() - 1 - i]) return false;
    return true;
}
/*删除l, r公共部分 @return l, r第一个不同的位置*/
inline int check(string& l, string& r) {
    int i = 0;
    for (; i < min(l.size(), r.size()); i++)
        if (l[i] != r[r.size() - 1 - i]) break;
    l = l.substr(i), r = r.substr(0, r.size() - i);
    return i;
}

priority_queue<Node, vector<Node>> q;
map<string, map<string, bool>> vis;
inline void dijkstra() {
    while (!q.empty()) {
        auto cur = q.top();
        q.pop();
        if (vis[cur.l][cur.r]) continue; //l, r 访问过
        if (isPalindrome(cur.l) && cur.r.empty()) { //左边是回文
            cout << cur.c << endl;
            return;
        } else if (isPalindrome(cur.r) && cur.l.empty()) { //右边是回文
            cout << cur.c << endl;
            return;
        } else if (cur.l.empty() && cur.r.empty()) { //都是空字符串
            cout << cur.c << endl;
            return;
        } else {
            for (int i = 1; i <= n; i++) {
                Node tmp(cur.c, cur.l, cur.r);
                if (tmp.l.size() >= tmp.r.size()) { //左边比右边长，加到右边
                    tmp.r = s[i] + tmp.r, tmp.c += cost[i];
                    int id = check(tmp.l, tmp.r);
                    if (id && (tmp.l.empty() || tmp.r.empty())) q.push(tmp);
                } else { //左边比右边短，加到左边
                    tmp.l = tmp.l + s[i], tmp.c += cost[i];
                    int id = check(tmp.l, tmp.r);
                    if (id && (tmp.l.empty() || tmp.r.empty())) q.push(tmp);
                }
            }
        }
        vis[cur.l][cur.r] = true;
    }
    cout << -1 << endl;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> s[i] >> cost[i];
        q.push(Node(cost[i], s[i], emps));
        q.push(Node(cost[i], emps, s[i]));
    }
    dijkstra();
    return 0;
}
```

# SCOI2007 最大土地面积
  - [题目链接](https://www.luogu.com.cn/problem/P4166)
  - 计算几何/凸包/旋转卡壳
<!-- more -->
# Description
选取平面上的 4 个点，使得围成的四边形的面积最大 ($n \le 2000$)。
# Solution
最大四边形的顶点一定在凸包上。
当凸包顶点数大于 3 时，先选取一条对角线，则其它两个点到对角线的距离具有单峰性，套旋转卡壳即可求出最大四边形面积。
当凸包顶点数等于 3 时，最大四边形面积为凸包面积减去内部点与凸包上的点构成的最小的三角形面积。
当凸包顶点数等于 2 时，面积为 0。
# Code
```cpp 最大内接四边形
#include <bits/stdc++.h>
#define PI acos(-1)

using namespace std;

constexpr int MAXN = 3e3 + 3;

struct Vec2 {
    Vec2() = default;
    Vec2(double _x, double _y) : x(_x), y(_y) {}

    friend inline bool operator<(const Vec2& a, const Vec2& b) {
        return fabs(a.x - b.x) < 1e-8 ? a.y < b.y : a.x < b.x;
    }

    friend inline Vec2 operator-(const Vec2& a, const Vec2& b) {
        return Vec2(a.x - b.x, a.y - b.y);
    }

    friend inline double operator*(const Vec2& a, const Vec2& b) {
        return a.x * b.y - a.y * b.x;  //×
    }
    double x = 0, y = 0;
} vec[MAXN], cov[MAXN];
int n, top, Up;

inline void convex() {
    top = 0, Up = 0;
    sort(vec + 1, vec + n + 1);
    for (int i = 1; i <= n; i++) {  //下凸壳
        while (top > 1 && (cov[top] - cov[top - 1]) * (vec[i] - cov[top]) < 1e-8)
            cov[top--] = Vec2(0, 0);
        cov[++top] = vec[i];
    }
    Up = top;                          //上凸壳起点
    for (int i = n - 1; i > 0; i--) {  //上凸壳
        while (top > Up && (cov[top] - cov[top - 1]) * (vec[i] - cov[top]) < 1e-8)
            cov[top--] = Vec2(0, 0);
        cov[++top] = vec[i];
    }
}

inline double calc(double res = .0) {
    if (top <= 3) return 0.0; //凸包只有2个点
    if (top == 4) ; //凸包只有3个点
    for (int i = 1; i < top; i++) {
        int up = (i + 2) % (top - 1) == 0 ? (i + 2) : (i + 2) % (top - 1);
        int down = i;
        for (int j = i + 2; j < i + top - 2; j++) {
            auto s = cov[i], t = cov[j % (top - 1) == 0 ? j : j % (top - 1)];
            while (true) {
                auto s1 = fabs((t - cov[up]) * (s - cov[up]));
                auto s2 = fabs((t - cov[up + 1]) * (s - cov[up + 1]));
                if (s1 < s2 + 1e-8) up = up % (top - 1) + 1;
                else break;
            }
            while (true) {
                auto s1 = fabs((t - cov[down]) * (s - cov[down]));
                auto s2 = fabs((t - cov[down + 1]) * (s - cov[down + 1]));
                if (s1 < s2 + 1e-8) down = down % (top - 1) + 1;
                else break;
            }
            res = max(res, fabs((cov[up]- s) * (cov[up] - t)) +
                               fabs((cov[down] - s) * (cov[down] - t)));
        }
    }
    return res / 2;
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n;
    for (int i = 1; i <= n; i++) cin >> vec[i].x >> vec[i].y;
    convex();
    cout << setprecision(3) << fixed << calc() << endl;;
    return 0;
}
```

# Matrix tree
<!-- more -->
## 矩阵树
定义图无向图 $G$ 的拉普拉斯矩阵 (Laplacian matrix) $L(G)$
$$
L_{ij} =
\begin{cases}
-m_{ij} & i \ne\ j, i 与 j 之间有 m_{ij}条边\\
deg(i) & i = j, deg(i) 为点 i 的度\\
\end{cases}
$$
则 $G$ 的生成树个数等于 $detL_0$，其中 $L_0$ 是去掉 $L$ 的 第 $i$ 行，第 $i$ 列得到的子矩阵 ($i$ 任意)。具体证明见 [参考资料](https://zhuanlan.zhihu.com/p/108209378)。
那么就可以化矩阵 $L_0$ 为上三角矩阵，即可求出 $detL_0$。
### Code
```cpp template
inline void add(int u, int v) { //加边
    G[u][u]++, G[v][v]++;
    G[u][v]--, G[v][u]--;
}

LL G[MAXN][MAXN];
inline LL Gauss(int tot) { //高斯消元
    LL ans = 1;
    for (int i = 1; i < tot; i++) {
        for (int j = i + 1; j < tot; j++)
            while (G[j][i]) {
                LL t = G[i][i] / G[j][i];
                for (int k = i; k < tot; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                ans = -ans;
            }
        ans = ans * G[i][i] % MOD;
    }
    return (ans + MOD) % MOD;
}
```
## 变元矩阵树
用于求所有生成树边权乘积的和。和矩阵树求法相同，不过行列式中 $G[i][i]$ 记录的是点 $i$ 所连的边权总和，$G[i][j]$ 记录的是 $i, j$ 之间边权的相反数之和。
### Code
```cpp tempalte
inline void add(int u, int v, double val) { //加边
    G[u][u] += val, G[v][v] += val;
    G[u][v] -= val, G[v][u] -= val;
}

inline double Gauss(int n) { //高斯消元
    double ans = 1;
    for (int i = 1; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (fabs(G[i][i]) < eps) swap(G[i], G[j]), ans = -ans;
            else break;
        }
        for (int j = i + 1; j < n; j++) {
            if (fabs(G[j][i]) < eps) continue;
            double tmp = G[j][i] / G[i][i];
            for (int k = i; k < n; k++)
                G[j][k] -= tmp * G[i][k];
        }
        ans = ans * G[i][i];
    }
    return ans;
}
```

## Cayley 定理
有 $p$ 个顶点的完全图 $K_p$，生成树的个数为 $p^{p - 2}$ 个 (行列式递推就行了)。

## 图联通方案数
有 $p$ 个顶点的图，已知有 $k$ 个连通块，如果仅将连通块看作点，则对应的生成树个数为 $p^{k - 2}$。[证明](https://oi-wiki.org/graph/prufer/#_3)。


