# A Acacius and String
[题目链接](https://codeforces.ml/contest/1379/problem/A)
## Solution
遇到可能匹配的位置 $i$ 暴力匹配即可。需要注意的是当前位置 $i$ 匹配后得到的串中  $abacaba$ 子串的个数可能大于 1，因此每次匹配成功后要检查子串 $abacaba$ 的个数。
## Code
```cpp Acacius and String
#include <bits/stdc++.h>

using namespace std;

int T, n;
string s;
string t = "abacaba";

int check(const string &s) {
    int cnt = 0;
    for (int i = 0; i <= n - 7; i++) {
        cnt++;
        for (int j = i; j < i + 7; j++) {
            if (s[j] != t[j - i]) {
                cnt--;
                break;
            }
        }
    }
    return cnt;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> T;
    while (T--) {
        cout << "\n";
        cin >> n >> s;
        int cnt = check(s);
        if (cnt > 1)
            cout << "No";
        else {
            if (cnt) {
                cout << "Yes\n";
                for (int i = 0; i < n; i++)
                    if (s[i] == '?') s[i] = 'z';
                cout << s;
            } else {
                bool flag = 0;
                for (int i = 0; i <= n - 7; i++) {
                    vector<int> v;
                    if (s[i] == t[0] || s[i] == '?') {
                        flag = 1;
                        for (int j = i; j < i + 7; j++) {
                            if (s[j] != t[j - i] && s[j] == '?')
                                s[j] = t[j - i], v.push_back(j);
                            else if (s[j] != t[j - i] && s[j] != '?') {
                                flag = 0;
                                break;
                            }
                        }
                    }
                    if (check(s) > 1) flag = 0;
                    if (flag) {
                        for (int j = 0; j < n; j++)
                            if (s[j] == '?') s[j] = 'z';
                        break;
                    } else
                        for (int j = 0; j < v.size(); j++) s[v[j]] = '?';
                    v.clear();
                }
                if (!flag)
                    cout << "No";
                else
                    cout << "Yes\n" << s;
            }
        }
    }
    return 0;
}
