using namespace std;
//求多边形最大内切圆半径 二分 + 半平面交
constexpr long double EPS = 1e-11;
constexpr int MAXN = 300;

struct Vec2 {  //点向量类
    Vec2() = default;
    Vec2(long double _x, long double _y) : x(_x), y(_y) {}
    /*Vec2 vector a - Vec2 vector b @return Vec2(x, y)*/
