## M CF1055F Tree and XOR
### Description
[CF1055F Tree and XOR](https://www.luogu.com.cn/problem/CF1055F)
### Solution
做法同 CF241B Friends。不过按照 CF241B Friends 的做法空间复杂度为 $O(61*N)$，显然不可能把整个 $trie$ 树存进去。实际上，只求第 $k$ 大的话有用的只有一层节点，当访问到下一层时，将上一层节点删除就好了。这样空间复杂度变为 $O(N)$，时间复杂度依然为$O(61*N)$。

注: 用系统自带的 $delete$ 时不知道为何 $RE$ 了，这里手写了 $new$ 和 $delete$ 操作。
### Code
```cpp CF1055F Tree and XOR
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int MAXN = 1e6 + 5;
const int BIT = 61;
int n, p[MAXN],u,tot[2];
ll k, val[MAXN], v;

template<class T>
void read(T &x, int f = 1) {
  char ch = getchar();
  x = 0;
  while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
  while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
  x *= f;
}

struct trie {
  trie* son[2];
  int sz;
  trie() {
    son[0] = son[1] = NULL;
    sz = 0;
  }
}*root,node[MAXN][2];

trie* newNode(trie* &cur,bool tag) {
  return cur=&node[tot[tag]++][tag];
}

void getKth(ll k) {
  ll ans = 0;
  newNode(root,0);
  trie *nodePtr[MAXN],*valPtr[MAXN];
  for (int i = 1; i <= n; i++) nodePtr[i] = valPtr[i] = root;
  for (int j = BIT; ~j; j--) {
    ll tmp = 0;
    bool tag = 0;
    for (int i = 1; i <= n; i++) {
      if (valPtr[i]->son[((val[i] >> j) & 1)] == NULL)
        newNode(valPtr[i]->son[((val[i] >> j) & 1)],j&1);
      valPtr[i] = valPtr[i]->son[((val[i] >> j) & 1)];
      valPtr[i]->sz++;
    }
    for (int i = 1; i <= n; i++)
      if (nodePtr[i] != NULL && nodePtr[i]->son[((val[i] >> j) & 1)] != NULL)
        tmp += nodePtr[i]->son[((val[i] >> j) & 1)]->sz;
    if (tmp < k) {
      k -= tmp, tag = 1;
      ans |= 1ll << j;
    }
    for (int i = 1; i <= n; i++)
      if (nodePtr[i] != NULL)
        nodePtr[i] = nodePtr[i]->son[((val[i] >> j) & 1) ^ tag];
    for(int i=0; i<=tot[(j&1)^1]; i++) {
      node[i][(j&1)^1].son[0]=node[i][(j&1)^1].son[1]=NULL;
      node[i][(j&1)^1].sz=0;
    }
    tot[(j&1)^1]=0;
  }
  cout << ans;
}

struct edge {
  int nxt, to;
  ll val;
} e[MAXN];

void addEdge(int from, int to, ll val) {
  static int t;
  e[t].val = val, e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}

void dfs(int now, ll v) {
  val[now] = v;
  for (int i = p[now]; ~i; i = e[i].nxt) {
    int to = e[i].to;
    if (!val[to]) dfs(to, v ^ e[i].val);
  }
}

int main() {
  read(n),read(k);
  memset(p, -1, sizeof(p));
  for (int i = 1; i <= n - 1; i++) {
    read(u), read(v);
    addEdge(u, i + 1, v);
  }
  dfs(1, 0);
  getKth(k);
  return 0;
}
```
# Level IV
可持久化 $Trie$ 树,原理和可持久化线段树相同

## A 最大异或和
### Description
[P4735 最大异或和](https://www.luogu.com.cn/problem/P4735)
### Solution
记 $preXor_i$ 表示前 $i$ 个数的异或和。对于查询操作，用异或性质转化一下，只需要求 $preXor_N⊕x$ 异或上 $preXor_{p-1}$ 的最大值（$l-1<=p<=r-1$），即在 $r-1$ 版本的 $trie$ 树中求插入时间大于等于 $l-1$ 的数与 $preXor_N⊕x$ 的最大异或和。因此每个点记一个 $last$，表示最后访问的时间，当 $last\ge l-1$时才可能被计入答案。 
### Code
```cpp 最大异或和
#include <bits/stdc++.h>

using namespace std;
const int MAXN = 3e5 + 5;

int n, m, l, r;
int preXor, x;
char type[2];
struct trie {
    trie *son[2];
    int last;
    trie() {
        son[0] = son[1] = NULL;
        last = 0;
    }
} node[MAXN * 48], *root[MAXN * 2];

void read(int &x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
}

trie *newNode(trie *&cur) {
    static int cntNode;
    return cur = &node[cntNode++];
}

void initR0() {
    trie *cur = newNode(root[0]);
    for (register int i = 23; i >= 0; i--) cur = newNode(cur->son[0]);
}

void build(const int &id) {
    trie *cur = newNode(root[id]), *pre = root[id - 1];
    for (register int i = 23; ~i; i--) {
        int now = (preXor >> i) & 1;
        if (pre != NULL) {
            cur->son[now ^ 1] = pre->son[now ^ 1];
            pre = pre->son[now];
        }
        cur = newNode(cur->son[now]);
        cur->last = id;
    }
}

void query(trie *cur, const int &last, const int &val) {
    int ans = 0;
    for (register int i = 23; ~i; i--) {
        int now = (val >> i) & 1;
        trie *tmp = cur->son[now ^ 1];
        if (tmp != NULL && tmp->last >= last)
            cur = tmp, ans += 1 << i;
        else
            cur = cur->son[now];
    }
    printf("%d\n", ans);
}

int main() {
    read(n), read(m);
    initR0();
    for (int i = 1; i <= n; i++) {
        read(x);
        preXor ^= x;
        build(i);
    }
    for (int i = 1; i <= m; i++) {
        scanf("%s", type);
        if (type[0] == 'A') {
            read(x);
            preXor ^= x;
            build(++n);
        } else {
            read(l), read(r), read(x);
            query(root[r - 1], l - 1, preXor ^ x);
        }
    }
    return 0;
}
```
## B TJOI2018 异或
### Description
[P4592 TJOI2018 异或](https://www.luogu.com.cn/problem/P4592)
### Solution
对于询问 1，按dfs序建立可持久化 $trie$ 树；对于询问 2，按深度建立可持久化 $trie$ 树，查询的时候求一下 $lca$ 即可。

### Code
```cpp TJOI2018 异或
#include <bits/stdc++.h>

using namespace std;

const int MAXN = 1e5 + 5;
const int BIT = 29;
int n, q, u, v, opt, z;
int p[MAXN], fa[MAXN][18], depth[MAXN];
int in[MAXN], out[MAXN], val[MAXN];

void read(int &x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct trie {
    trie *son[2];
    int last;
    trie() {
        son[0] = son[1] = NULL;
        last = 0;
    }
} node[MAXN * (BIT + 2)][2], *root[MAXN][2];

trie *newNode(trie *&cur, const bool &tag) {
    static int cntNode[2];
    return cur = &node[cntNode[tag]++][tag];
}

void initRoot() {
    trie *cur = newNode(root[1][0], 0);
    trie *tmp = newNode(root[1][1], 1);
    for (int i = BIT; ~i; i--) {
        int now = (val[1] >> i) & 1;
        cur = newNode(cur->son[now], 0);
        tmp = newNode(tmp->son[now], 1);
        cur->last = tmp->last = 1;
    }
}

void insert(trie *pre, trie *cur, int val, int last, bool tag) {
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (pre != NULL) {
            cur->son[now ^ 1] = pre->son[now ^ 1];
            pre = pre->son[now];
        }
        cur = newNode(cur->son[now], tag);
        cur->last = last;
    }
}

int query(trie *cur, int val, int last) {
    int ans = 0;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (cur->son[now ^ 1] != NULL && cur->son[now ^ 1]->last >= last)
            cur = cur->son[now ^ 1], ans += 1 << i;
        else if (cur->son[now] != NULL && cur->son[now]->last >= last)
            cur = cur->son[now];
        else
            break;
    }
    return ans;
}

struct edge {
    int to, nxt;
} e[MAXN * 2];

void addEdge(int from, int to) {
    static int t;
    e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}

void dfs1(const int &now) {
    static int times = 1;
    in[now] = times++;
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (!in[to]) {
            insert(root[times - 1][0], newNode(root[times][0], 0), val[to],
                   times, 0);
            dfs1(to);
        }
    }
    out[now] = times;
}

void dfs2(int now, int d) {
    depth[now] = d;
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (!depth[to]) {
            fa[to][0] = now;
            insert(root[now][1], newNode(root[to][1], 1), val[to], d + 1, 1);
            dfs2(to, d + 1);
        }
    }
}

void getFa() {
    for (int j = 1; (1 << j) <= n; j++)
        for (int i = 1; i <= n; i++)
            if (fa[i][j - 1]) fa[i][j] = fa[fa[i][j - 1]][j - 1];
}

int lca(int a, int b, int i = 0) {
    if (depth[a] < depth[b]) swap(a, b);
    for (; (1 << i) <= depth[a]; i++)
        ;
    for (int j = i - 1; j >= 0; j--)
        if (depth[a] - depth[b] >= (1 << j)) a = fa[a][j];
    if (a == b) return a;
    for (int j = i - 1; j >= 0; j--)
        if (fa[a][j] && fa[a][j] != fa[b][j]) a = fa[a][j], b = fa[b][j];
    return fa[a][0];
}

int main() {
    read(n), read(q);
    for (int i = 1; i <= n; i++) read(val[i]);
    memset(p, -1, sizeof(p));
    for (int i = 1; i <= n - 1; i++) {
        read(u), read(v);
        addEdge(u, v), addEdge(v, u);
    }
    initRoot();
    dfs1(1);
    dfs2(1, 1);
    getFa();
    for (int i = 1; i <= q; i++) {
        read(opt);
        if (opt == 1) {
            read(u), read(z);
            printf("%d\n", query(root[out[u] - 1][0], z, in[u]));
        } else {
            read(u), read(v), read(z);
            int tmp = lca(u, v);
            printf("%d\n", max(query(root[u][1], z, depth[tmp]),
                               query(root[v][1], z, depth[tmp])));
        }
    }
    return 0;
}
```
## C JSOI2015 字符串树
### Description
[P6088 JSOI2015 字符串树](https://www.luogu.com.cn/problem/P6088)
### Solution
$dfs$ 时，对每个点，在其父亲版本的基础上建立可持久化 $trie$ 树。令$cnt_i$ 表示从根到节点到 $i$ 有多少字符串以 $S$ 为前缀。显然，答案具有可加性，$u,v$ 之间以 $S$ 为前缀的字符串数目为 $cnt_u + cnt_v - 2*cnt_{lca(u,v)}$，查询的时候求一下 $lca$ 即可。
### Code
```cpp JSOI2015 字符串树
#include <bits/stdc++.h>
using namespace std;
const int MAXN = 1e5 + 5;
int n, m, u, v;
char s[11];
int p[MAXN], fa[MAXN][17], depth[MAXN];
void read(int& x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}
struct trie {
    trie* son[26];
    int cnt;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = NULL;
        cnt = 0;
    }
} node[MAXN * 10], *root[MAXN];
trie* newNode(trie*& cur) {
    static int cntNode;
    return cur = &node[cntNode++];
}
struct edge {
    int to, nxt;
    string s;
} e[MAXN * 2];
void addEdge(int from, int to, const string& s) {
    static int t;
    e[t].s = s, e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}
void build(trie* pre, trie* cur, const string& s) {
    for (int i = 0; i < s.size(); i++) {
        int to = s[i] - 'a';
        if (pre != NULL) {
            for (int j = 0; j < 26; j++) cur->son[j] = pre->son[j];
            pre = pre->son[to];
        }
        cur = newNode(cur->son[to]);
        cur->cnt = (pre != NULL ? pre->cnt : 0) + 1;
    }
}
int query(trie* cur, const string& s) {
    for (int i = 0; i < s.size(); i++) {
        int to = s[i] - 'a';
        if (cur->son[to] != NULL)
            cur = cur->son[to];
        else
            return 0;
    }
    return cur->cnt;
}
void dfs(const int& now, int d) {
    depth[now] = d;
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (!depth[to] && to != 1) {
            fa[to][0] = now;
            build(root[now], newNode(root[to]), e[i].s);
            dfs(to, d + 1);
        }
    }
}
void getFa() {
    for (int j = 1; (1 << j) <= n; j++)
        for (int i = 1; i <= n; i++)
            if (fa[i][j - 1]) fa[i][j] = fa[fa[i][j - 1]][j - 1];
}
int lca(int a, int b, int i = 0) {
    if (depth[a] < depth[b]) swap(a, b);
    for (; (1 << i) <= depth[a]; i++);
    for (int j = i - 1; j >= 0; j--)
        if (depth[a] - depth[b] >= (1 << j)) a = fa[a][j];
    if (a == b) return a;
    for (int j = i - 1; j >= 0; j--)
        if (fa[a][j] && fa[a][j] != fa[b][j]) a = fa[a][j], b = fa[b][j];
    return fa[a][0];
}
int main() {
    memset(p, -1, sizeof(p));
    read(n);
    for (int i = 1; i <= n - 1; i++) {
        read(u), read(v), scanf("%s", s);
        addEdge(u, v, s), addEdge(v, u, s);
    }
    newNode(root[1]);
    dfs(1, 0);
    getFa();
    read(m);
    for (int i = 1; i <= m; i++) {
        read(u), read(v), scanf("%s", s);
        printf("%d\n", query(root[u], s) + query(root[v], s) -
                           2 * query(root[lca(u, v)], s));
    }
    return 0;
}
```
## C HEOI2013 ALO
### Description
[P4098 HEOI2013 ALO](https://www.luogu.com.cn/problem/P4098)
### Solution
首先建立可持久化 $trie$ 树。对于 $a_i$，设左边第一个比它大的数下标为 $l_1$, 左边第二个比它大的数下标为 $l_2$；右边第一个比它大的数下标为 $r_1$, 左边第二个比它大的数下标为 $r_2$。显然，能让 $a_i$ 为次大值的最大区间为 $[l_1+1,r_2-1]$ 和 $[l_2+1,r_1-1]$。只需预处理出 $l_{1,2}$ 和 $r_{1,2}$，接下来在可持久化 $trie$ 上贪心地求最大值即可。

考虑如何求 $l_{1,2}$ 和 $r_{1,2}$。将 $a_1$ 到  $a_n$ 按从大到小排序，同时记录原来的下标 $b_i$。排序后按顺序将 $b_i$ 插入 $set$ 中。易知 $set$ 中任意元素 $b_k$ 对应值 $a_{b_k}$一定大于当前位置 $b_i$ 对应值 $a_{b_i}$(题目约定数组 $a$ 中的元素不重复), 且 $set$ 已按下标排好序，用 lower_bound 和 upper_bound 容易求出当前下标 $b_i$ 的前驱和后继。


### Code
```cpp HEOI2013 ALO
#include <bits/stdc++.h>

using namespace std;
const int MAXN = 5e4 + 5;
const int BIT = 30;
int n, a[MAXN], b[MAXN], l[MAXN][3], r[MAXN][3];

template <class T>
void read(T &x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct trie {
    trie *son[2];
    int last;
    trie() {
        son[0] = son[1] = NULL;
        last = 0;
    }
} * root[MAXN];

void insert(int id) {
    trie *cur = root[id] = new trie, *pre = root[id - 1];
    for (int i = BIT; ~i; i--) {
        int now = (a[id] >> i) & 1;
        if (pre != NULL) {
            cur->son[now ^ 1] = pre->son[now ^ 1];
            pre = pre->son[now];
        }
        cur->son[now] = new trie;
        cur = cur->son[now];
        cur->last = id;
    }
}

int query(trie *cur, int last, int val) {
    int ans = 0;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (cur->son[now ^ 1] != NULL && cur->son[now ^ 1]->last >= last)
            cur = cur->son[now ^ 1], ans |= 1 << i;
        else
            cur = cur->son[now];
    }
    return ans;
}

bool cmp(const int &x, const int &y) { return a[x] > a[y]; }

int main() {
    read(n);
    root[0] = new trie;
    for (int i = 1; i <= n; i++) read(a[i]), insert(i), b[i] = i;
    sort(b + 1, b + n + 1, cmp);
    set<int> s;
    set<int>::iterator it;
    s.insert(-2), s.insert(-1), s.insert(n + 1), s.insert(n + 2);
    for (int i = 1; i <= n; i++) {
        s.insert(b[i]);
        it = s.lower_bound(b[i]);
        l[b[i]][1] = max(0, *--it);
        l[b[i]][2] = max(0, *--it);
        it = s.upper_bound(b[i]);
        r[b[i]][1] = min(n + 1, *it);
        r[b[i]][2] = min(n + 1, *++it);
    }
    int ans = 0;
    for (int i = 1; i <= n; i++)
        ans = max(ans, max(query(root[r[i][1] - 1], l[i][2] + 1, a[i]),
                           query(root[r[i][2] - 1], l[i][1] + 1, a[i])));
    printf("%d", ans);
    return 0;
}
```

# 合金
  - [题目链接](https://www.luogu.com.cn/problem/P4049)
  - 计算几何/凸包
  - 图论/Floyed
<!-- more -->
# Description
有 m 种原材料由铁、铝、锡组成的合金，不同合金有不同铁铝锡的比重 $a_i$, $b_i$, $c_i$。将每种原材料取出一定量，经过融解、混合，得到新的合金。现需要 $n$ 种合金，铁铝锡的比重为 $d_i$, $e_i$, $f_i$。求最少需要的原材料种数。
# Solution
设有合金 $(a_1, b_1, c_1)$ 与 $(a_2, b_2, c_2)$，欲合成合金 $(d, e, f)$。
则有
$$
\left\{
\begin{array}{lr}
k_1 (a_1, b_1, c_1)+k_2 (a_2, b_2, c_2)=(d, e, f)\\
k_1 (1-b_1-a_1)+k_2 (1-b_2-a_2)=1-d-e\\
\end{array}
\right.
$$
如果只考虑2维，那么有
$$
\left\{
\begin{array}{lr}
k_1 (a_1, b_1)+k_2 (a_2, b_2)=(d, e)\\
k_1+k_2+k_1 (-b_1-a_1)+k_2 (-b_2-a_2)=1-d-e\\
\end{array}
\right.
$$
可得
$$
\left\{
\begin{array}{lr}
k_1 (a_1, b_1)+k_2 (a_2, b_2)=(d, e)\\
k1 + k2 = 1\\
\end{array}
\right.
$$
即
- 若 2 种合金 $(a_1, b_1, c_1)$，$(a_2, b_2, c_2)$ 能合成合金 $(d, e, f)$，则 $(a_1, b_1)$、$(a_2, b_2)$、$(d, e)$ 三点共线，且点 $(d, e)$ 位于两点之间。
- 若有 3 种合金，对应三个点，则先连接其中两点，两点所连线段上的点都可以被表示；再将线段上的点与第三个点连接，所连的线段上的点均可被选取。即三点所围的点都能被表示出来。

于是问题转化为求原材料合金对应二维坐标的凸包(点最少)，该凸包能否将所需要的材料对应二维坐标的凸包给围住。
对于两个坐标，如果所需要的材料对应的坐标均在所连向量的左侧(通过向量外积判断)，则两点连边单向边，长度为 1。通过弗洛伊德最小环可得到最少的原料数。

注意：
- 若所需材料的坐标在原材料坐标所连直线上(此时向量外积为0)，则需通过向量内积判断是否在原材料坐标所连线段上
- 注意比较时的精度 $epsilon$


# Code
```cpp 合金
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 505;
constexpr double EPSILON = 1e-15;

struct Vector {
    Vector() = default;
    Vector(double _x, double _y) : x(_x), y(_y) {}

    friend inline double operator* /*×*/(const Vector& a, const Vector& b) {
        return a.x * b.y - a.y * b.x; //向量外积
    }

    friend inline Vector operator-(const Vector& a, const Vector& b) {
        return Vector(a.x - b.x, a.y - b.y);
    }

    friend inline double dotProduct(const Vector& a, const Vector& b) {
        return a.x * b.x + a.y * b.y; //向量内积
    }

    double x = .0, y = .0;
} mat[MAXN], pro[MAXN];  // material and product

int n, m, ans(0x3f3f3f3f), dis[MAXN][MAXN];

inline void init() {
    memset(dis, 0x3f, sizeof(dis));
    for (int i = 1; i <= m; i++)
        for (int j = 1; j <= m; j++) {
            bool connect = true;
            for (int k = 1; k <= n; k++) {//判断是否能作为凸包的边
                double cross = (mat[j] - mat[i]) * (pro[k] - mat[i]);
                double dot = dotProduct(mat[j] - pro[k], mat[i] - pro[k]);
                if (cross < -EPSILON || (abs(cross) < EPSILON && dot > EPSILON))
                    connect = false;
            }
            if (connect) dis[i][j] = 1;
        }
}

inline void floyed() { //floyed求最小环
    for (int k = 1; k <= m; k++)
        for (int i = 1; i <= m; i++)
            for (int j = 1; j <= m; j++) {
                dis[i][j] = min(dis[i][j], dis[i][k] + dis[k][j]);
            }
    for (int i = 1; i <= m; i++) ans = min(ans, dis[i][i]);
    cout << (ans == 0x3f3f3f3f ? -1 : ans) << endl;
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> m >> n;

    double a, b, c;
    for (int i = 1; i <= m; i++) {
        cin >> a >> b >> c;
        mat[i] = Vector(a, b);
    }
    for (int i = 1; i <= n; i++) {
        cin >> a >> b >> c;
        pro[i] = Vector(a, b);
    }
    init();
    floyed();
    return 0;
}
```

# 国家集训队 种树
  - [题目链接](https://www.luogu.com.cn/problem/P1792)
  - 数据结构/优先队列/链表
  - STL/list
  - 贪心
<!-- more -->
# Description
有一个环形广场上有 $n$ 个种树位置，顺时针编号 1 到 $n$。每个位置有美观度 $A_i$，选取不相邻的 $m$ 个位置种树，求最大美观度和。
# Solution
思路同[APIO/CTSC 2007 数据备份](http://shaun-shane.vercel.app/2020/07/17/shu-ju-bei-fen/)，只不过需通过环形链表解决，且当 $n / 2 < m$ 时无解。
# Code
## 环形双向链表
与非环形双向链表不同，$head$ 与 $tail$ 不用作为虚拟节点。链表建立时 $tail->next = head$ 且 $head->prev = tail$。删除和插入操作与非双向链表类似。
```cpp 环形双向链表
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 2e5 + 5;

int n, m, a[MAXN], cnt, ans;

struct ListNode {
    ListNode() = default;
    bool operator<(const ListNode& other) const {
        return this->data == other.data ? this->id < other.id : this->data < other.data;
    }
    ListNode *prev = NULL, *next = NULL, *cur = NULL;
    int data = 0, id = -1;
};
map<int, bool> deleted;
priority_queue<ListNode> q;

struct CycleList {
    CycleList() = default;

    ListNode* insert(int data, int id) {
        auto newNode = new ListNode();
        newNode->data = data, newNode->id = id, newNode->cur = newNode;
        if (head == NULL) head = tail = newNode;
        newNode->prev = tail, tail->next = newNode, tail = newNode;
        tail->next = head, head->prev = tail;
        return newNode;
    }

    ListNode* erase(ListNode* cur) {
        auto prev = cur->prev, next = cur->next;
        int data = prev->data + next->data - cur->data;
        deleted[prev->id] = deleted[cur->id] = deleted[next->id] = true;

        auto newNode = new ListNode();
        newNode->data = data, newNode->id = cnt++, newNode->cur = newNode;
        prev->prev->next = newNode, newNode->prev = prev->prev;
        next->next->prev = newNode, newNode->next = next->next;
        return newNode;
    }

    ListNode *head = NULL, *tail = NULL;
} lst;

void calcA(int tot = 0) {
    while (!q.empty() && tot < m) {
        auto cur = q.top();
        q.pop();
        if (deleted[cur.id]) continue;
        ans += cur.data, tot++;
        auto newNode = lst.erase(cur.cur);
        q.push(*newNode);
    }
}

int main() {
    scanf("%d %d", &n, &m);
    if (n / 2 < m) return printf("Error!\n"), 0;
    for (int i = 0; i < n; i++) {
        scanf("%d", a + i);
        auto newNode = i == n - 1 ? lst.insert(a[i], cnt++) : lst.insert(a[i], cnt++);
        q.push(*newNode);
    }
    calcA();
    printf("%d\n", ans);
    return 0;
}
```
## STL 环形链表
$STL$ 的 $list$ 是环形链表。list.end() 的下一个迭代器是 list.begin()，list.begin() 的上一个迭代器是 list.end()。删除过程中，需特判当前迭代器是否为 list.end()，若是，则选取下一个迭代器进行删除。另外需注意：由于最后一次删除操作可能导致 $list$ 为空，要特判一下。
```cpp STL 环形链表
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 2e5 + 5;

int n, m, a[MAXN], ans, cnt;

struct ListNode {
    ListNode() = default;
    ListNode(int _data, int _id) : data(_data), id(_id) {}
    bool operator<(const ListNode &other) const {
        return this->data == other.data ? this->id < other.id : this->data < other.data;
    }
    int data = 0, id = -1;
    list<ListNode>::iterator itr;
};
list<ListNode> lst;
priority_queue<ListNode> q;
map<int, bool> deleted;

inline void calcA(int tot = 0) {
    while (!q.empty() && tot < m) {
        auto cur = q.top();
        q.pop();
        if (deleted[cur.id]) continue;
        ans += cur.data, tot++;
        if (tot == m) break;
        //将相邻三个节点删除 并用新节点替换 带反悔贪心
        int data(0);
        auto itr = --cur.itr;
        if (itr == lst.end()) --itr;

        data += itr->data, deleted[itr->id] = true, itr = lst.erase(itr);
        if (itr == lst.end()) ++itr;

        data -= itr->data, deleted[itr->id] = true, itr = lst.erase(itr);
        if (itr == lst.end()) ++itr;

        if (itr == lst.end()) cout << "err" << endl;
        data += itr->data, deleted[itr->id] = true, itr = lst.erase(itr);
        //将相邻三个节点删除 并用新节点替换 带反悔贪心
        auto newNode = ListNode(data, cnt++);
        newNode.itr = lst.insert(itr, newNode);
        q.push(newNode);
    }
}

int main() {
    scanf("%d %d", &n, &m);
    if (n / 2 < m) return printf("Error!\n"), 0;
    for (int i = 0; i < n; ++i) {
        scanf("%d", a + i);
        auto newNode = ListNode(a[i], cnt++);
        newNode.itr = lst.insert(lst.end(), newNode); //末尾插入
        q.push(newNode); //加入优先队列
    } 
    calcA(); //计算美观度sigma_Ai
    printf("%d\n", ans);
    return 0;
}
```

# 数据备份
  - [题目链接](https://www.luogu.com.cn/problem/P3620)
  - 数据结构/优先队列/链表
  - STL/list
  - 贪心
<!-- more -->
# Description
有 $N$ 座办公楼位于同一条街上，已知每座办公楼距离大街起点的距离。现要用 $K$ 条网络电缆将办公楼连接，且任意一个办公楼都属于唯一配对组(即连接的 $2K$ 个办公楼一定是相异的)。求 $K$ 条网络电缆最小的长度总和。
# Solution
容易发现，最优解中每两个配对的办公楼一定是相邻的。于是先求出两个相邻办公楼之间的距离，记为 $D_1, D_2, D_3, ..., D_{N - 1}$。于是问题可以转化为：从数列 $D$ 中选取不超过 $K$ 个不相邻的数，使它们的和最小。

考虑贪心：
  - 如果 $K=1$，答案显然是数列 D 中的最小值
  - 如果 $K=2$，可以证明答案是以下两种情况之一：
    - 选取 $D_i$，以及除了 $D_{i-1}, D_i, D_{i+1}$ 之外其他数中的最小值
    - 选取最小值 $D_i$左右两侧的两个数，即 $D_{i-1}$ 和 $D_{i+1}$
    - 即最优解中，最小值左右两侧的数要么选，要么都不选
  - 为防止选取局部最优解，可以先选取数列 $D$ 中的最小值 $D_i$，然后把 $D_{i-1}, D_i, D_{i+1}$ 删除，把 $D_{i-1}+D_{i+1}-D_i$ 插入到数列 $D$ 中之前执行删除的位置。这样如果之后选了 $D_{i-1}+D_{i+1}-D_i$，相当于没有选 $D_i$，换上了 $D_{i-1}$ 和 $D_{i+1}$。

于是可建立一个初始有 $N-1$ 个节点的链表，链表节点记录数值 $D_i$，节点编号 $Id_i$，以及链表节点指针或对应的迭代器。再建立一个优先队列(小根堆)，将链表节点存入。K 次操作中，取出堆顶的链表节点 $ListNode$，在链表中删除 $ListNode->prev$ 和 $ListNode->next$，并创建新节点(数值为 $ListNode->prev->data+ListNode->next->data-ListNode->data$)插入链表和优先队列。

注意：为防止越界或简化边界情况判断，可以在链表起始和末尾插入极大值。

# Code
## 指针版双向链表
```cpp 指针版双向链表
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 1e5 + 5;
constexpr LL INF = 1e18;

LL n, k, dis[MAXN], ans, cnt;

struct ListNode {
    ListNode() = default;
    bool operator<(const ListNode &other) const {
        return this->data == other.data ? this->id > other.id : this->data > other.data;
    }
    ListNode *prev = NULL, *next = NULL, *cur = NULL;
    LL data = 0, id = -1;
};
map<int, bool> deleted;

struct List {
    List() { //构造函数
        this->head = new ListNode(), this->tail = new ListNode();
        this->head->next = this->tail;
        this->tail->prev = this->head;
    }

    ListNode *insert(LL data) { //插入值，返回节点指针
        ListNode *cur = new ListNode();
        cur->data = data, cur->id = cnt++, cur->cur = cur;
        tail->prev->next = cur, cur->prev = tail->prev;
        cur->next = tail, tail->prev = cur;
        return cur;
    }

    ListNode *erase(ListNode *cur) { //删除节点，返回新节点指针
        LL data = cur->prev->data + cur->next->data - cur->data;
        ListNode *newListNode = new ListNode();
        newListNode->cur = newListNode;
        newListNode->data = data, newListNode->id = cnt++;

        ListNode *prev = cur->prev, *next = cur->next;
        prev->prev->next = newListNode, newListNode->prev = prev->prev;
        next->next->prev = newListNode, newListNode->next = next->next;

        deleted[prev->id] = deleted[next->id] = deleted[cur->id] = true;
        return newListNode;
    }

    ~List() {}
    ListNode *head = NULL, *tail = NULL;
} lst;

priority_queue<ListNode> q;
inline void calcLen(int tot = 0) {
    while (!q.empty() && tot < k) {
        ListNode* cur = q.top().cur;
        q.pop();
        if (deleted[cur->id]) continue;
        ans += cur->data, tot++;
        ListNode *newListNode = lst.erase(cur);
        q.push(*newListNode); //插入新节点
    }
}

int main() {
    scanf("%lld %lld", &n, &k);
    for (int i = 0; i < n; ++i) scanf("%lld", dis + i);
    lst.insert(INF); //防止越界 简化边界判断
    for (int i = 0; i < n - 1; ++i) q.push(*lst.insert(dis[i + 1] - dis[i]));
    lst.insert(INF); //防止越界 简化边界判断
    calcLen(); //计算总长度
    printf("%lld\n", ans);
    return 0;
}
```
## STL list
$STL$ 的 $list$ 为 环形双向链表, 本题中用到以下功能。
- 通过 $iterator--$ 或 $iterator++$ 获得 $prev$ 或 $next$ 的迭代器。
- insert() 成员函数在指定位置处插入值，并返回插入的元素所对应的的迭代器
- erase() 成员函数对指定位置进行删除，返回删除的元素后一个位置的迭代器

```cpp STL list
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 1e5 + 5;
constexpr LL INF = 1e15;

LL n, k, dis[MAXN], ans, cnt;

struct ListNode {
    ListNode() = default;
    ListNode(LL _data, LL _id) : data(_data), id(_id) {}
    bool operator<(const ListNode &other) const {
        return this->data == other.data ? this->id > other.id : this->data > other.data;
    }
    LL data = INF, id = -1;
    list<ListNode>::iterator itr;
};
list<ListNode> lst;
priority_queue<ListNode> q;
map<LL, bool> deleted;

inline void calcLen(int tot = 0) {
    while (!q.empty() && tot < k) {
        auto cur = q.top();
        q.pop();
        if (deleted[cur.id]) continue;
        ans += cur.data, tot++;
        //删除
        auto itr = cur.itr;
        --itr; //得到cur->prev的迭代器
        LL data = itr->data; deleted[itr->id] = true, itr = lst.erase(itr);
        data -= itr->data, deleted[itr->id] = true, itr = lst.erase(itr);
        data += itr->data, deleted[itr->id] = true, itr = lst.erase(itr);
        //删除
        auto newNode = ListNode(data, cnt++);
        newNode.itr = lst.insert(itr, newNode);
        q.push(newNode);
    }
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> k;
    for (int i = 0; i < n; ++i) cin >> dis[i];
    lst.emplace_back(ListNode(INF, cnt++)); //防止越界 简化边界判断
    for (int i = 0; i < n - 1; ++i) {
        auto newNode = ListNode(dis[i + 1] - dis[i], cnt++);
        newNode.itr = lst.insert(lst.end(), newNode); //末尾插入
        q.push(newNode);
    }
    lst.emplace_back(ListNode(INF, cnt++)); //防止越界 简化边界判断
    calcLen();
    cout << ans << endl;
    return 0;
}
```

