               (vec[stk[top]] - vec[stk[top - 1]]) * (vec[i] - vec[stk[top]]) <= 0)
            used[stk[top--]] = false;
        used[i] = true;
        stk[++top] = i;
    }
    int tmp = top;
    for (int i = cnt - 1; i > 0; i--) { //上凸壳
        if (!used[i]) {
            while (top > tmp && (vec[stk[top]] - vec[stk[top - 1]]) *
                                        (vec[i] - vec[stk[top]]) <= 0)
                used[stk[top--]] = false;
            used[i] = true;
            stk[++top] = i;
        }
