    double n, st(0);
    string s;
    cin >> n >> s;
    for (int i = 0; i < s.size(); i++) {
        if (s[i] == 'S') {
            vec[++cnt] = Vec2(st, 0);
            vec[++cnt] = Vec2(st, 2);
            vec[++cnt] = Vec2(st + 2, 0);
            vec[++cnt] = Vec2(st + 2, 2);
        } else if (s[i] == 'T') {
            vec[++cnt] = Vec2(st, 0);
            vec[++cnt] = Vec2(st + 2, 0);
            vec[++cnt] = Vec2(st + 1, sqrt(3.0));
        } else {
            for (int j = 1; j <= M; j++) {
