# 小Z的袜子
  - [题目链接](https://www.luogu.com.cn/problem/P1494)
  - 数据结构/分块/莫队

<!-- more -->
# Description
多组询问求给定区间 $[l_i,r_i]$ 中取出相同两个数的概率。
# Solution
  - 设区间内某种颜色的数目为 $cnt_{color}$。
  - 则概率为 $\frac{\Sigma{}cnt_{color}(cnt_{color} − 1)}{(r − l + 1)(r − l)}$。
  - 将询问分块，一般取块的长度为 $sqrt(n)$ 或 $\frac{n}{sqrt(2 * m / 3)}$。询问所在的块由询问左端点$l_i$ 决定。
    ```cpp
    read(n), read(m), Len = n / sqrt(m * 2.0 / 3);
    for (int i = 1; i <= n; i++) cin >> c[i];
    for (int i = 1; i <= m; i++) 
        read(Q[i].l), read(Q[i].r), Q[i].id = i, Q[i].block = Q[i].l / Len;
    sort(Q + 1, Q + m + 1, cmp1);
    ```
  - 排序: 询问 $q_i$，$q_j$所在块相同则按其右端点排序，否则按块的编号升序排序。
    ```cpp
    struct query {
        int l, r, id, block, x/*记录询问分子*/, y/*记录询问分母*/;
    }Q[MAXN];

    inline bool cmp1 (const query &a, const query &b) {
      return (a.block== b.block) ? a.r < b.r : a.block < b.block;
    }
    inline bool cmp2 (const query &a, const query &b) { //按照原始顺序排序
        return a.id < b.id;
    }
    ```
  - 询问时，用 $l$，$r$ 记录上一次询问的位置(初始均为 1)，不断加减扩展即可(求的是 $\Delta$)。

# Code
```cpp 小Z的袜子
#include<bits/stdc++.h>
#define int long long

constexpr int MAXN = 5e4 + 4;

using namespace std;

template <typename T> inline void read(T &x) {
    int f = 1; x = 0; 
    char ch = getchar();
    while (!isdigit(ch)) f = (ch == '-') ? -1 : 1, ch = getchar();
    while (isdigit(ch)) x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

int n, m, Len, l, r, ans;
int c[MAXN], cnt[MAXN];
struct query {
    int l, r, id, block, x/*记录询问分子*/, y/*记录询问分母*/;
}Q[MAXN];

inline bool cmp1 (const query &a, const query &b) {
    return (a.block== b.block) ? a.r < b.r : a.block < b.block;
}

inline bool cmp2 (const query &a, const query &b) { //按照原始顺序排序
    return a.id < b.id;
}

inline int gcd(int x, int y) {
    return !y ? x : gcd(y, x % y);
}

signed main(){
    read(n), read(m), Len = n / sqrt(m * 2.0 / 3);
    for (int i = 1; i <= n; i++) read(c[i]);
    for (int i = 1; i <= m; i++) 
        read(Q[i].l), read(Q[i].r), Q[i].id = i, Q[i].block = Q[i].l / Len;
    sort(Q + 1, Q + m + 1, cmp1);
    l = 1, r = 0;
    for (int i = 1; i <= m; i++) {
        while (r < Q[i].r) {
            r++;
            ans -= cnt[c[r]] * (cnt[c[r]] - 1);
            cnt[c[r]]++;
            ans += cnt[c[r]] * (cnt[c[r]] - 1);
        }
        while (r > Q[i].r) {
            ans -= cnt[c[r]] * (cnt[c[r]] - 1);
            cnt[c[r]]--;
            ans += cnt[c[r]] * (cnt[c[r]] - 1);
            r--;
        }
        while (l < Q[i].l) {
            ans -= cnt[c[l]] * (cnt[c[l]] - 1);
            cnt[c[l]]--;
            ans += cnt[c[l]] * (cnt[c[l]] - 1);
            l++;
        }
        while (l > Q[i].l) {
            l--;
            ans -= cnt[c[l]] * (cnt[c[l]] - 1);
            cnt[c[l]]++;
            ans += cnt[c[l]] * (cnt[c[l]] - 1);
        }
        Q[i].x = ans, Q[i].y = (Q[i].r - Q[i].l + 1) * (Q[i].r - Q[i].l);
    }
    sort(Q + 1, Q + m + 1, cmp2);
    for (int i = 1; i <= m; i++)
        if (Q[i].l == Q[i].r) puts("0/1");
        else printf("%lld/%lld\n", Q[i].x / gcd(Q[i].x, Q[i].y), Q[i].y / gcd(Q[i].x, Q[i].y));
    return 0;
}
```

# Best Cow Line G
  - [题目链接](https://www.luogu.com.cn/problem/P2870)
  - Hash/字符串Hash
  - 二分答案
  - 倍增

<!-- more -->
# Description
给定长度为 $N$ 的字符串 $S$，每次可从 $S$ 的两端选取一个字符插入空字符串 $T$ 尾部。求字典序最小的字符串 $T$。
# Solution
考虑贪心：比较当前 $S$ 与 $reverse(S)$ 的字典序，如果 $S$ 的字典序小则从 $S$ 头部取出字符；否则从尾部取出。
本题数据加强，逐位比较会被卡。需 $hash$ + 二分或倍增求出最长相同前缀子串，比较下一个位置的大小。
注：字符串 $hash$(%) 不能直接用来比较字符串大小。
# Code
## 二分子串长度
```cpp Best Cow Line G
#include<bits/stdc++.h>

typedef unsigned long long uLL;
constexpr int MAXN = 5e5 + 5;
constexpr uLL base = 13331;

using namespace std;

int n;
uLL H1[MAXN], H2[MAXN], P[MAXN] = {1};
char s[MAXN], revs[MAXN];
string ans;

inline void Init() {
    for (int i = 1; i <= n; i++) P[i] = P[i - 1] * base;
    for (int i = 1; i <= n; i++) H1[i] = H1[i - 1] * base + s[i] - 'A' + 1;
    for (int i = 1; i <= n; i++) H2[i] = H2[i - 1] * base + revs[i] - 'A' + 1;
}

inline uLL getHash(int l, int r, uLL * H) {
    return H[r] - H[l - 1] * P[r - l + 1];
}

inline bool compare(int l, int r) {
    int L = 0, R = r - l, len = -1;
    while (L <= R) {
        int mid = (L + R) >> 1;
        if (getHash(l, l + mid, H1) == getHash(n - r + 1, n - r + 1 + mid, H2)) 
            len = mid, L = mid + 1;
        else R = mid - 1;
    }
    return s[l + len + 1] < s[r - len - 1];
}

int main(){
    cin >> n;
    for (int i = 1; i <= n; i++) 
        getchar(), s[i] = getchar(), revs[n - i + 1] = s[i];
    Init();
    int l = 1, r = n;
    while (l <= r) {
        if (compare(l, r)) ans += s[l], l++;
        else ans += s[r], r--;
    }
    for (int i = 0; i < n; i++) {
        if (i && i % 80 == 0) putchar('\n');
        putchar(ans[i]);
    }
    return 0;
}
```
## 倍增
```cpp Best Cow Line G
#include <bits/stdc++.h>


typedef unsigned long long uLL;
constexpr uLL base = 13331;
constexpr int MAXN = 5e5 + 5;

using namespace std;

int n;
uLL H1[MAXN], H2[MAXN], P[MAXN] = {1};
char s[MAXN], revs[MAXN];
string ans;

inline void Init() {
    for (int i = 1; i <= n; i++) P[i] = P[i - 1] * base;
    for (int i = 1; i <= n; i++) H1[i] = H1[i - 1] * base + s[i] - 'A' + 1;
    for (int i = 1; i <= n; i++) H2[i] = H2[i - 1] * base + revs[i] - 'A' + 1;
}

inline uLL getHash(int l, int r, uLL* H) {
    return H[r] - H[l - 1] * P[r - l + 1];
}

inline bool compare(int l, int r) {
    int len = 1, Lst = l - 1, Rst = n - r;
    while (len) {
        if (Lst + len <= r &&
            getHash(l, Lst + len, H1) == getHash(n - r + 1, Rst + len, H2)) {
            Lst += len, Rst += len, len <<= 1;
        } else
            len >>= 1;
    }
    return s[Lst + 1] < revs[Rst + 1];
}

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++)
        getchar(), s[i] = getchar(), revs[n - i + 1] = s[i];
    Init();
    int l = 1, r = n;
    while (l <= r) {
        if (compare(l, r)) ans += s[l], l++;
        else ans += s[r], r--;
    }
    for (int i = 0; i < n; i++) {
        if (i && i % 80 == 0) putchar('\n');
        putchar(ans[i]);
    }
    return 0;
}
